    // ...
}
（5）Response
http 响应参数结构体.
type Response struct {
    // 请求状态，200 为 请求成功
    StatusCode int    // e.g. 200
    // http 协议，如：HTTP/1.0
    Proto      string // e.g. &quot;HTTP/1.0&quot;
    // 请求头
    Header Header
    // 响应参数内容  
    Body io.ReadCloser
    // 指向请求参数
    Request *Request
    // ...
}
3.2 方法链路总览
客户端发起一次 http 请求大致分为几个步骤：

构造 http 请求参数
获取用于与服务端交互的 tcp 连接
通过 tcp 连接发送请求参数
通过 tcp 连接接收响应结果

整体方法链路如下图：

3.3 Client.Post
调用 net/http 包下的公开方法 Post 时，需要传入服务端地址 url，请求参数格式 contentType 以及请求参数的 io reader.
方法中会使用包下的单例客户端 DefaultClient 处理这次请求.
var DefaultClient = &amp;Client{}

func Post(url, contentType string, body io.Reader) (resp *Response, err error) {
    return DefaultClient.Post(url, contentType, body)
}
在 Client.Post 方法中，首先会结合用户的入参，构造出完整的请求参数 Request；继而通过 Client.Do 方法，处理这笔请求.
func (c *Client) Post(url, contentType string, body io.Reader) (resp *Response, err error) {
    req, err := NewRequest(&quot;POST&quot;, url, body)
    // ...
    req.Header.Set(&quot;Content-Type&quot;, contentType)
    return c.Do(req)
}
3.4 NewRequest
NewRequestWithContext 方法中，根据用户传入的 url、method等信息，构造了 Request 实例.
func NewRequestWithContext(ctx context.Context, method, url string, body io.Reader) (*Request, error) {
    // ...
    u, err := urlpkg.Parse(url)
    // ...
    rc, ok := body.(io.ReadCloser)
    // ...
    req := &amp;Request{
        ctx:        ctx,
        Method:     method,
        URL:        u,
        // ...
        Header:     make(Header),
        Body:       rc,
        Host:       u.Host,
    }
    // ...
    return req, nil
}
3.5 Client.Do

发送请求方法时，经由 Client.Do、Client.do 辗转，继而步入到 Client.send 方法中.
func (c *Client) Do(req *Request) (*Response, error) {
    return c.do(req)
}

func (c *Client) do(req *Request) (retres *Response, reterr error) {
    var (
        deadline      = c.deadline()
        resp          *Response
        // ...
    )    
    for {
        // ...
        var err error       
        if resp, didTimeout, err = c.send(req, deadline); err != nil {
            // ...
        }
        // ...
    }
}
在 Client.send 方法中，会在通过 send 方法发送请求的前后，分别对 cookie 进行更新.
func (c *Client) send(req *Request, deadline time.Time) (resp *Response, didTimeout func() bool, err error) {
    // 设置 cookie 到请求头中
    if c.Jar != nil {
        for _, cookie := range c.Jar.Cookies(req.URL) {
            req.AddCookie(cookie)
        }
    }
    // 发送请求
    resp, didTimeout, err = send(req, c.transport(), deadline)
    if err != nil {
        return nil, didTimeout, err
    }
    // 更新 resp 的 cookie 到请求头中
    if c.Jar != nil {
        if rc := resp.Cookies(); len(rc) &gt; 0 {
            c.Jar.SetCookies(req.URL, rc)
        }
    }
    return resp, nil, nil
}
在调用 send 方法时，需要注入 RoundTripper 模块，默认会使用全局单例 DefaultTransport 进行注入，核心逻辑位于 Transport.RoundTrip 方法中，其中分为两个步骤：

获取/构造 tcp 连接
通过 tcp 连接完成与服务端的交互

var DefaultTransport RoundTripper = &amp;Transport{
    // ...
    DialContext: defaultTransportDialContext(&amp;net.Dialer{
        Timeout:   30 * time.Second,
        KeepAlive: 30 * time.Second,
    }),
    // ...
}

func (c *Client) transport() RoundTripper {
    if c.Transport != nil {
        return c.Transport
    }
    return DefaultTransport
}
func send(ireq *Request, rt RoundTripper, deadline time.Time) (resp *Response, didTimeout func() bool, err error) {
    // ...
    resp, err = rt.RoundTrip(req)
    // ...
    return resp, nil, nil
}
func (t *Transport) RoundTrip(req *Request) (*Response, error) {
    return t.roundTrip(req)
}

func (t *Transport) roundTrip(req *Request) (*Response, error) {
    // ...
    for {          
        // ...    
        treq := &amp;transportRequest{Request: req, trace: trace, cancelKey: cancelKey}      
        // ...
        pconn, err := t.getConn(treq, cm)        
        // ...
        resp, err = pconn.roundTrip(treq)          
        // ...
    }
}

3.6 Transport.getConn

获取 tcp 连接的策略分为两步：

通过 queueForIdleConn 方法，尝试复用采用相同协议、访问相同服务端地址的空闲连接
倘若无可用连接，则通过 queueForDial 方法，异步创建一个新的连接，并通过接收 ready channel 信号的方式，确认构造连接的工作已经完成.

func (t *Transport) getConn(treq *transportRequest, cm connectMethod) (pc *persistConn, err error) {
    // 获取连接的请求参数体
    w := &amp;wantConn{
        cm:         cm,
        // key 由 http 协议、服务端地址等信息组成
        key:        cm.key(),
        ctx:        ctx,
        // 标识连接构造成功的信号发射器
        ready:      make(chan struct{}, 1),
    }
    // 倘若连接获取失败，在 wantConn.cancel 方法中，会尝试将 tcp 连接放回队列中以供后续复用
    defer func() {
        if err != nil {
            w.cancel(t, err)
        }
    }()
    // 尝试复用指向相同服务端地址的空闲连接
    if delivered := t.queueForIdleConn(w); delivered {
        pc := w.pc
        // ...
        return pc, nil
    }
    // 异步构造新的连接
    t.queueForDial(w)
    select {
    // 通过阻塞等待信号的方式，等待连接获取完成
    case &lt;-w.ready:
        // ...
        return w.pc, w.err
    // ...
    }
}
（1）复用连接

尝试从 Transport.idleConn 中获取指向同一服务端的空闲连接 persisConn
获取到连接后会调用 wantConn.tryDeliver 方法将连接绑定到 wantConn 请求参数上
绑定成功后，会关闭 wantConn.ready channel，以唤醒阻塞读取该 channel 的 goroutine

func (t *Transport) queueForIdleConn(w *wantConn) (delivered bool) {
    // ...
    if list, ok := t.idleConn[w.key]; ok {
        // ...
        for len(list) &gt; 0 &amp;&amp; !stop {
            pconn := list[len(list)-1]
            // ...
            delivered = w.tryDeliver(pconn, nil)
            if delivered {
                // ...
                list = list[:len(list)-1]               
            }
            stop = true
        }
        // ...
        if stop {
            return delivered
        }
    }

    // ...    
    return false
}
func (w *wantConn) tryDeliver(pc *persistConn, err error) bool {
    w.mu.Lock()
    defer w.mu.Unlock()
    // ...
    w.pc = pc
    w.err = err
    // ...
    close(w.ready)
    return true
}
（2）创建连接
在 queueForDial 方法会异步调用 Transport.dialConnFor 方法，创建新的 tcp 连接. 由于是异步操作，所以在上游会通过读 channel 的方式，等待创建操作完成.
这里之所以采用异步操作进行连接创建，有两部分原因：

一个 tcp 连接并不是一个静态的数据结构，它是有生命周期的，创建过程中会为其创建负责读写的两个守护协程，伴随而生
在上游 Transport.queueForIdleConn 方法中，当通过 select 多路复用的方式，接收到其他终止信号时，可以提前调用 wantConn.cancel 方法打断创建连接的 goroutine. 相比于串行化执行而言，这种异步交互的模式，具有更高的灵活度

func (t *Transport) queueForDial(w *wantConn) {
    // ...
    go t.dialConnFor(w) 
    // ...
}
Transport.dialConnFor 方法中，首先调用 Transport.dialConn 创建 tcp 连接 persisConn，接着执行 wantConn.tryDeliver 方法，将连接绑定到 wantConn 上，然后通过关闭 ready channel 操作唤醒上游读 ready channel 的 goroutine.
func (t *Transport) dialConnFor(w *wantConn) {
    // ...
    pc, err := t.dialConn(w.ctx, w.cm)
    delivered := w.tryDeliver(pc, err)
    // ...
}

Transport.dialConn 方法包含了创建连接的核心逻辑：

调用 Transport.dial 方法，最终通过 Tranport.DialContext 成员函数，创建好 tcp 连接，封装到 persistConn 当中
异步启动连接的伴生读写协程 readLoop 和 writeLoop 方法，组成提交请求、接收响应的循环

func (t *Transport) dialConn(ctx context.Context, cm connectMethod) (pconn *persistConn, err error) {
    pconn = &amp;persistConn{
        t:             t,
        reqch:         make(chan requestAndChan, 1),
        writech:       make(chan writeRequest, 1),
        // ...
    }

    conn, err := t.dial(ctx, &quot;tcp&quot;, cm.addr())
    // ...
    pconn.conn = conn      
    // ...

    go pconn.readLoop()
    go pconn.writeLoop()
    return pconn, nil
}

func (t *Transport) dial(ctx context.Context, network, addr string) (net.Conn, error) {
    // ...
    return t.DialContext(ctx, network, addr)
    // ...
}
在伴生读协程 persisConn.readLoop 方法中，会读取来自服务端的响应，并添加到 persistConn.reqCh 中，供上游 persistConn.roundTrip 方法接收.
func (pc *persistConn) readLoop() { 
    // ...
    alive := true
    for alive {
        // ...
        rc := &lt;-pc.reqch
        // ...
        var resp *Response
        // ...
        resp, err = pc.readResponse(rc, trace)
        // ...
        select{
            rc.ch &lt;- responseAndError{res: resp}:
            // ...
        }
        // ...        
    }

}
在伴生协协程 persisConn.writeLoop方法中，会通过 persistConn.writech 读取到客户端提交的请求，然后将其发送到服务端.
func (pc *persistConn) writeLoop() {    
    for {
        select {
        case wr := &lt;-pc.writech:
            // ...
            err := wr.req.Request.write(pc.bw, pc.isProxy, wr.req.extra, pc.waitForContinue(wr.continueCh))
            // ...       
    }
}
（3）归还连接
有复用连接的能力，就必然存在归还连接的机制.
首先，在构造新连接中途，倘若被打断，则可能会将连接放回队列以供复用：
func (t *Transport) getConn(treq *transportRequest, cm connectMethod) (pc *persistConn, err error) {
    // ...
    // 倘若连接获取失败，在 wantConn.cancel 方法中，会尝试将 tcp 连接放回队列中以供后续复用
    defer func() {
        if err != nil {
            w.cancel(t, err)
        }
    }()
    // ...
}
func (w *wantConn) cancel(t *Transport, err error) {
   // ...
    if pc != nil {
        t.putOrCloseIdleConn(pc)
    }
}
func (t *Transport) tryPutIdleConn(pconn *persistConn) error {
    // ...
    key := pconn.cacheKey
    // ...
    t.idleConn[key] = append(idles, pconn)
    // ...
    return nil
}
其次，倘若与服务端的一轮交互流程结束，也会将连接放回队列以供复用
func (pc *persistConn) readLoop() {
    tryPutIdleConn := func(trace *httptrace.ClientTrace) bool {
        if err := pc.t.tryPutIdleConn(pc); err != nil {
            // ...
        }
        // ...
    }

    // ...
    alive := true
    for alive {
        // ...
        select {
        case bodyEOF := &lt;-waitForBodyRead:
            // ...
            tryPutIdleConn(trace)
            // ...
        }           
    }

}
func (t *Transport) putOrCloseIdleConn(pconn *persistConn) {
    if err := t.tryPutIdleConn(pconn); err != nil {
        pconn.close(err)
    }
}
3.7 persistConn.roundTrip
3.6 小节中谈到，一个连接 persistConn 是一个具有生命特征的角色. 它本身伴有 readLoop 和 writeLoop 两个协程，与应用者之间通过 channel 进行读写交互.
而其中扮演应用者这一角色的，正式本小节谈到的主流程中的方法：persistConn.roundTrip：

首先将 http 请求通过 persistConn.writech 发送给连接的守护协程 writeLoop，并进一步传送到服务端
其次通过读取 resc channel，接收由守护协程 readLoop 代理转发的客户端响应数据.

func (pc *persistConn) roundTrip(req *transportRequest) (resp *Response, err error) {
    // ...
    pc.writech &lt;- writeRequest{req, writeErrCh, continueCh}
    resc := make(chan responseAndError)
    pc.reqch &lt;- requestAndChan{
        req:        req.Request,
        cancelKey:  req.cancelKey,
        ch:         resc,
        // ...
    }
    // ...
    for {       
        select {
        // ...
        case re := &lt;-resc:
            // ...
            return re.res, nil
        // ...
        }
    }
}

编程语言/Go/高级/语言基础/反射.content:
反射
从反射对象到接口值的过程是从接口值到反射对象的镜面过程，两个过程都需要经历两次转换：

从接口值到反射对象：

从基本类型到接口类型的类型转换；
从接口类型到反射对象的转换；


从反射对象到接口值：

反射对象转换成接口类型；
通过显式类型转换变成原始类型；



[reflect](golang.org/pkg/reflect/) 实现了运行时的反射能力，能够让程序操作不同类型的对象1。反射包中有两对非常重要的函数和类型，两个函数分别是：

[reflect.TypeOf](draveness.me/golang/tree/reflect.TypeOf) 能获取类型信息；
[reflect.ValueOf](draveness.me/golang/tree/reflect.ValueOf) 能获取数据的运行时表示；

Type和Value的数据结构
类型 [reflect.Type](draveness.me/golang/tree/reflect.Type)是反射包定义的一个接口，我们可以使用 [reflect.TypeOf](draveness.me/golang/tree/reflect.TypeOf)函数获取任意变量的类型
type Type interface {
        Align() int
        FieldAlign() int
        Method(int) Method
        MethodByName(string) (Method, bool)
        NumMethod() int
        ...
        Implements(u Type) bool
        ...
}

反射包中 [reflect.Value](draveness.me/golang/tree/reflect.Value)的类型与 [reflect.Type](draveness.me/golang/tree/reflect.Type)不同，它被声明成了结构体。这个结构体没有对外暴露的字段，但是提供了获取或者写入数据的方法：
type Value struct {
        // 包含过滤的或者未导出的字段
}

func (v Value) Addr() Value
func (v Value) Bool() bool
func (v Value) Bytes() []byte
...

三大法则
运行时反射是程序在运行期间检查其自身结构的一种方式。反射带来的灵活性是一把双刃剑，反射作为一种元编程方式可以减少重复代码2，但是过量的使用反射会使我们的程序逻辑变得难以理解并且运行缓慢。我们在这一节中会介绍 Go 语言反射的三大法则3，其中包括：

从 interface{} 变量可以反射出反射对象；
从反射对象可以获取 interface{} 变量；
要修改反射对象，其值必须可设置；

第一法则
reflect.TypeOf和reflect.ValueOf函数的入参都是interface{}类型，由于Go参数是值传递，所以会先转换为interface{}类型，最后才得出Type和Value
第二法则
反射的第二法则是我们可以从反射对象可以获取 interface{}变量。既然能够将接口类型的变量转换成反射对象，那么一定需要其他方法将反射对象还原成接口类型的变量，[reflec](golang.org/pkg/reflect/)中的 [reflect.Value.Interface](draveness.me/golang/tree/reflect.Value.Interface)就能完成这项工作。
从反射对象到接口值的过程是从接口值到反射对象的镜面过程，两个过程都需要经历两次转换：

从接口值到反射对象：

从基本类型到接口类型的类型转换；
从接口类型到反射对象的转换；


从反射对象到接口值：

反射对象转换成接口类型；
通过显式类型转换变成原始类型；




第三法则
由于 Go 语言的函数调用都是传值的，所以我们得到的反射对象跟最开始的变量没有任何关系，那么直接修改反射对象无法改变原始变量，程序为了防止错误就会崩溃。所以就如下方式进行修改：
func main() {
	i := 1
	v := reflect.ValueOf(&amp;i)
	v.Elem().SetInt(10)
	fmt.Println(i)
}

$ go run reflect.go
10

反射对象生成
Go 语言的 interface{}类型在语言内部是通过 [reflect.emptyInterface](draveness.me/golang/tree/reflect.emptyInterface) 结体表示的，其中的 rtype字段用于表示变量的类型，另一个 word字段指向内部封装的数据：
type emptyInterface struct {
	typ  *rtype
	word unsafe.Pointer
}

TypeOf函数将传入的变量隐式转换成 [reflect.emptyInterface](draveness.me/golang/tree/reflect.emptyInterface)类型并获取其中存储的类型信息 [reflect.rtype](draveness.me/golang/tree/reflect.rtype)：
func TypeOf(i interface{}) Type {
	eface := *(*emptyInterface)(unsafe.Pointer(&amp;i))
	return toType(eface.typ)
}

func toType(t *rtype) Type {
	if t == nil {
		return nil
	}
	return t
}

[reflect.rtype](draveness.me/golang/tree/reflect.rtype)是一个实现了 [reflect.Type](draveness.me/golang/tree/reflect.Type)接口的结构体
ValueOf函数先调用了 [reflect.escapes](draveness.me/golang/tree/reflect.escapes) 保证当前值逃逸到堆上，然后通过 [reflect.unpackEface](draveness.me/golang/tree/reflect.unpackEface)
 从接口中获取 [reflect.Value](draveness.me/golang/tree/reflect.Value)结构体，[reflect.unpackEface](draveness.me/golang/tree/reflect.unpackEface)会将传入的接口转换成 [reflect.emptyInterface](draveness.me/golang/tree/reflect.emptyInterface)，然后将具体类型和指针包装成 [reflect.Value](draveness.me/golang/tree/reflect.Value)结构体后返回
func ValueOf(i interface{}) Value {
	if i == nil {
		return Value{}
	}

	escapes(i)

	return unpackEface(i)
}

func unpackEface(i interface{}) Value {
	e := (*emptyInterface)(unsafe.Pointer(&amp;i))
	t := e.typ
	if t == nil {
		return Value{}
	}
	f := flag(t.Kind())
	if ifaceIndir(t) {
		f |= flagIndir
	}
	return Value{t, e.word, f}
}

更新变量
反射对象进行变量更新时，会生成新的Value对象，然后通过对象的指针替代，实现变量更新
[reflect.Value.assignTo](draveness.me/golang/tree/reflect.Value.assignTo) 会根据当前和被设置的反射对象类型创建一个新的 [reflect.Value](draveness.me/golang/tree/reflect.Value) 结构体：

如果两个反射对象的类型是可以被直接替换，就会直接返回目标反射对象；
如果当前反射对象是接口并且目标对象实现了接口，就会把目标对象简单包装成接口值；

在变量更新的过程中，[reflect.Value.assignTo](draveness.me/golang/tree/reflect.Value.assignTo) 返回的 [reflect.Value](draveness.me/golang/tree/reflect.Value) 中的指针会覆盖当前反射对象中的指针实现变量的更新。
实现协议
[reflect](golang.org/pkg/reflect/)包还为我们提供了 [reflect.rtype.Implements](draveness.me/golang/tree/reflect.rtype.Implements)方法可以用于判断某些类型是否遵循特定的接口。
[reflect.rtype.Implements](draveness.me/golang/tree/reflect.rtype.Implements)方法的工作原理：
func (t *rtype) Implements(u Type) bool {
	if u == nil {
		panic(&quot;reflect: nil type passed to Type.Implements&quot;)
	}
	if u.Kind() != Interface {
		panic(&quot;reflect: non-interface type passed to Type.Implements&quot;)
	}
	return implements(u.(*rtype), t)
}

[reflect.rtype.Implements](draveness.me/golang/tree/reflect.rtype.Implements)会检查传入的类型是不是接口，如果不是接口或者是空值就会直接崩溃并中止当前程序。在参数没有问题的情况下，上述方法会调用私有函数 [reflect.implements](draveness.me/golang/tree/reflect.implements)判断类型之间是否有实现关系：
func implements(T, V *rtype) bool {
	t := (*interfaceType)(unsafe.Pointer(T))
	if len(t.methods) == 0 {
		return true
	}
	...
	v := V.uncommon()
	i := 0
	vmethods := v.methods()
	for j := 0; j &lt; int(v.mcount); j++ {
		tm := &amp;t.methods[i]
		tmName := t.nameOff(tm.name)
		vm := vmethods[j]
		vmName := V.nameOff(vm.name)
		if vmName.name() == tmName.name() &amp;&amp; V.typeOff(vm.mtyp) == t.typeOff(tm.typ) {
			if i++; i &gt;= len(t.methods) {
				return true
			}
		}
	}
	return false
}


如果接口中不包含任何方法，就意味着这是一个空的接口，任意类型都自动实现该接口，这时会直接返回 true
在其他情况下，由于方法都是按照字母序存储的，[reflect.implements](draveness.me/golang/tree/reflect.implements)会维护两个用于遍历接口和类型方法的索引 i和 j判断类型是否实现了接口，因为最多只会进行 n次比较（类型的方法数量），所以整个过程的时间复杂度是 O(n)O(n)

方法调用
反射的方法调用，是在静态语言中，动态调用函数，所以会进行参数校验，准备参数，函数调用，以及返回值处理。
也就是动态处理函数的参数检查，栈帧分布
